export const RUN_EVENT_SCHEMA_V1 = "nexus.run-event.v1" as const;
export type RunEventSchemaVersion = typeof RUN_EVENT_SCHEMA_V1;

export type RunId = string & { readonly __brand: "RunId" };
export type SourceId = string & { readonly __brand: "SourceId" };
export type SeqNum = number & { readonly __brand: "SeqNum" };

export const runId = (raw: string): RunId => raw as RunId;
export const sourceId = (raw: string): SourceId => raw as SourceId;
export const seqNum = (raw: number): SeqNum => raw as SeqNum;

export type LineStream = "stdout" | "stderr";

export type Severity = "trace" | "debug" | "info" | "warn" | "error";

export type PhaseName =
  | "discover"
  | "print_meta"
  | "tensors"
  | "kv_reserve"
  | "context_build"
  | "warmup"
  | "ready";

export type PhaseState = "started" | "in_progress" | "completed" | "failed";

export type MetricUnit =
  | "bytes"
  | "bytes_per_second"
  | "tokens"
  | "tokens_per_second"
  | "milliseconds"
  | "percent"
  | "count"
  | "other";

export type TensorGroup =
  | "embed"
  | "attn"
  | "ffn"
  | "norm"
  | "kv_cache"
  | "output"
  | "other";

export type AllocationTarget =
  | { kind: "gpu"; device: number }
  | { kind: "cpu" }
  | { kind: "cpu_mmap" }
  | { kind: "pinned" }
  | { kind: "mixed" };

export type WidgetKind =
  | "lattice"
  | "download"
  | "kv_cache"
  | "token_rate"
  | "file_tree"
  | "json_rpc"
  | "other";

export type ErrorReason =
  | "vram_oom"
  | "ram_oom"
  | "file_not_found"
  | "gguf_parse"
  | "corruption_suspected"
  | "quantization_mismatch"
  | "backend_init"
  | "kv_cache_init"
  | "alloc_failure_partial"
  | "user_cancelled"
  | "other";

export type GapReason =
  | "n_layer_missing"
  | "tensor_histogram_missing"
  | "transport_drop"
  | "scraper_lag"
  | "worker_crash"
  | "other";

export interface AnsiSpan {
  text: string;
  fg?: string;
  bg?: string;
  bold?: boolean;
  dim?: boolean;
  italic?: boolean;
}

interface RunEventBase {
  schema: RunEventSchemaVersion;
  seq: number;
  ts_ms: number;
  run_id: string;
  source: string;
}

export interface LineEvent extends RunEventBase {
  kind: "line";
  stream: LineStream;
  severity: Severity;
  text: string;
  spans?: AnsiSpan[];
}

export interface PhaseEvent extends RunEventBase {
  kind: "phase";
  phase: PhaseName;
  state: PhaseState;
  progress?: number;
  summary?: string;
}

export interface MetricEvent extends RunEventBase {
  kind: "metric";
  name: string;
  value: number;
  unit: MetricUnit;
  labels: Record<string, string>;
  window_ms?: number;
}

export interface TensorAllocateEvent extends RunEventBase {
  kind: "tensor_allocate";
  layer?: number;
  group: TensorGroup;
  bytes: number;
  target: AllocationTarget;
  tensor_name?: string;
  dtype?: string;
}

export interface ArtifactEvent extends RunEventBase {
  kind: "artifact";
  path: string;
  mime: string;
  bytes?: number;
  digest_sha256?: string;
}

export interface WidgetEvent extends RunEventBase {
  kind: "widget";
  widget: WidgetKind;
  props: unknown;
}

export interface ErrorEvent extends RunEventBase {
  kind: "error";
  reason: ErrorReason;
  layer?: number;
  group?: TensorGroup;
  device?: string;
  message: string;
  suggestion?: string;
}

export interface GapEvent extends RunEventBase {
  kind: "gap";
  from_seq: number;
  to_seq: number;
  reason: GapReason;
}

export interface ScraperUnknownEvent extends RunEventBase {
  kind: "scraper_unknown";
  raw_line: string;
  scraper: string;
}

export type RunEventItem =
  | LineEvent
  | PhaseEvent
  | MetricEvent
  | TensorAllocateEvent
  | ArtifactEvent
  | WidgetEvent
  | ErrorEvent
  | GapEvent
  | ScraperUnknownEvent;

export interface EventBatch {
  schema: RunEventSchemaVersion;
  run_id: string;
  batch_seq_start: number;
  batch_seq_end: number;
  events: RunEventItem[];
}

export interface RunBucket {
  start_ts_ms: number;
  end_ts_ms: number;
  counts: { info: number; warn: number; error: number };
  metrics: Record<string, { sum: number; max: number; count: number }>;
}

export interface SeqRange {
  from: number;
  to: number;
}

export interface GapReport {
  runId: RunId;
  gaps: { from_seq: number; to_seq: number; reason: GapReason; source: string }[];
}

export interface MetricSample {
  metric_name: string;
  value: number;
  ts_ms: number;
  available: boolean;
}

